231	fn get_socket_path() -> Result<PathBuf> {
232	    let xdg = xdg::BaseDirectories::with_prefix("vibe-attack");
233	
234	    xdg.place_runtime_file("vibe-attack.sock")
235	        .context("Failed to place UDS socket in runtime directory")
