1	/// End-to-end integration tests for the M008 control surface over a real UDS socket.
2	///
3	/// Each test spins up `spawn_control_listener` against a live tokio runtime, waits
4	/// for the socket file to appear, sends commands via the blocking `send_command`
5	/// client on a `spawn_blocking` task, and asserts both wire-level responses and
6	/// in-process side-effects on the shared `DaemonHandle`.
7	///
8	/// Tests are serialised with `#[serial]` to prevent socket-path races.
9	/// If `XDG_RUNTIME_DIR` is absent (bare CI), the bind will fail and the test
10	/// returns early (no panic) so the suite remains green.
11	use std::sync::{mpsc, Arc};
12	use serial_test::serial;
13	use vibe_attack::control::{
14	    client::{is_daemon_running, send_command},
15	    protocol::{ActivationMode, ControlRequest, ControlResponse},
16	    spawn_control_listener, DaemonHandle,
17	};
18	use vibe_attack::input::inject::MacroCmd;
19	use vibe_attack::pipeline::coordinator::RuntimeCommand;
20	use vibe_attack::pipeline::dispatcher::Dispatcher;
21	
22	// ── Drop guard ───────────────────────────────────────────────────────────────
23	
24	/// Removes the socket file on drop so a panicking assertion doesn't leave a stale
25	/// socket that breaks the next test run.
26	struct SocketGuard(std::path::PathBuf);
27	
28	impl Drop for SocketGuard {
29	    fn drop(&mut self) {
30	        let _ = std::fs::remove_file(&self.0);
31	    }
32	}
33	
34	/// Resolve the server-side socket path (place_runtime_file creates the XDG dir).
35	/// Returns `None` when XDG_RUNTIME_DIR is absent so tests can skip gracefully.
36	fn socket_path() -> Option<std::path::PathBuf> {
37	    let xdg = xdg::BaseDirectories::with_prefix("vibe-attack");
38	    xdg.place_runtime_file("vibe-attack.sock").ok()
39	}
