43	/// Build a `DaemonHandle` wired to a fresh runtime channel.
44	/// Returns the handle and the Receiver end so the test can drain sent commands.
45	fn make_handle_with_runtime_tx() -> (DaemonHandle, mpsc::Receiver<RuntimeCommand>) {
46	    let (macro_tx, _macro_rx) = mpsc::channel::<MacroCmd>();
47	    let dispatcher = Arc::new(Dispatcher::new(0.5, vec![], macro_tx, 50, 30));
48	    let (rt_tx, rt_rx) = mpsc::channel::<RuntimeCommand>();
49	    let handle = DaemonHandle::new(dispatcher).with_runtime_tx(rt_tx);
50	    (handle, rt_rx)
51	}
