55	/// Prove the full round-trip: SetMode travels over the socket, the handler caches
56	/// `active_mode` on the handle, forwards a `RuntimeCommand::SetMode` to the
57	/// runtime channel, and a subsequent Status query reflects the new mode.
58	#[tokio::test]
59	#[serial]
60	async fn set_mode_round_trip_via_socket() {
61	    let path = match socket_path() {
62	        Some(p) => p,
63	        None => {
64	            eprintln!("set_mode_round_trip_via_socket: XDG_RUNTIME_DIR absent — skipping");
65	            return;
66	        }
67	    };
68	
69	    let (handle, rt_rx) = make_handle_with_runtime_tx();
70	
71	    // Confirm default mode is Ptt before any command.
72	    assert_eq!(
73	        *handle.active_mode.read().unwrap(),
74	        ActivationMode::Ptt,
75	        "initial active_mode must be Ptt"
76	    );
77	
78	    // Bind the control listener; skip if bind fails (e.g. runtime dir not writable).
79	    if let Err(e) = spawn_control_listener(handle.clone()).await {
80	        eprintln!("set_mode_round_trip_via_socket: bind failed ({e}) — skipping");
81	        return;
82	    }
83	
84	    let _guard = SocketGuard(path.clone());
85	
86	    // Poll until is_daemon_running() returns true (socket file exists).
87	    let mut ready = false;
88	    for _ in 0..50 {
89	        if is_daemon_running() {
90	            ready = true;
91	            break;
92	        }
93	        tokio::time::sleep(std::time::Duration::from_millis(20)).await;
94	    }
95	    if !ready {
96	        eprintln!("set_mode_round_trip_via_socket: socket never became ready — skipping");
97	        return;
98	    }
99	
100	    // Send SetMode{Wake} over the socket from a blocking thread.
101	    let resp = tokio::task::spawn_blocking(|| {
102	        send_command(ControlRequest::SetMode { mode: ActivationMode::Wake })
103	    })
104	    .await
105	    .expect("spawn_blocking panicked")
106	    .expect("send_command failed");
107	
108	    assert!(
109	        matches!(resp, ControlResponse::Ok),
110	        "expected Ok from SetMode, got: {resp:?}"
111	    );
112	
113	    // The handler must have forwarded exactly one RuntimeCommand::SetMode(Wake).
114	    let mut forwarded = Vec::new();
115	    while let Ok(cmd) = rt_rx.try_recv() {
116	        forwarded.push(cmd);
117	    }
118	    assert_eq!(forwarded.len(), 1, "expected exactly one RuntimeCommand forwarded, got {}", forwarded.len());
119	    assert!(
120	        matches!(forwarded[0], RuntimeCommand::SetMode(ActivationMode::Wake)),
121	        "expected SetMode(Wake), got: {:?}", forwarded[0]
122	    );
123	
124	    // The cache on the handle must reflect the new mode.
125	    assert_eq!(
126	        *handle.active_mode.read().unwrap(),
127	        ActivationMode::Wake,
128	        "handle active_mode not updated after SetMode"
129	    );
130	
131	    // Status query over the wire must echo back the cached mode.
132	    let status_resp = tokio::task::spawn_blocking(|| {
133	        send_command(ControlRequest::Status)
134	    })
135	    .await
136	    .expect("spawn_blocking panicked")
137	    .expect("send_command(Status) failed");
138	
139	    match status_resp {
140	        ControlResponse::StatusData(s) => {
141	            assert_eq!(
142	                s.active_mode,
143	                ActivationMode::Wake,
144	                "Status response active_mode should reflect the SetMode we sent"
145	            );
146	        }
147	        other => panic!("expected StatusData from Status query, got: {other:?}"),
148	    }
149	}
