151	/// Prove that SetThreshold travels over the socket and the handler forwards a
152	/// `RuntimeCommand::SetThreshold` with the correct value to the runtime channel.
153	/// The dispatcher's internal threshold is updated by the coordinator when it drains
154	/// the channel (tested in tests/runtime_commands.rs); here we only assert the wire
155	/// and channel path.
156	#[tokio::test]
157	#[serial]
158	async fn set_threshold_via_socket_updates_dispatcher() {
159	    let path = match socket_path() {
160	        Some(p) => p,
161	        None => {
162	            eprintln!("set_threshold_via_socket_updates_dispatcher: XDG_RUNTIME_DIR absent — skipping");
163	            return;
164	        }
165	    };
166	
167	    let (handle, rt_rx) = make_handle_with_runtime_tx();
168	
169	    if let Err(e) = spawn_control_listener(handle.clone()).await {
170	        eprintln!("set_threshold_via_socket_updates_dispatcher: bind failed ({e}) — skipping");
171	        return;
172	    }
173	
174	    let _guard = SocketGuard(path.clone());
175	
176	    let mut ready = false;
177	    for _ in 0..50 {
178	        if is_daemon_running() {
179	            ready = true;
180	            break;
181	        }
182	        tokio::time::sleep(std::time::Duration::from_millis(20)).await;
183	    }
184	    if !ready {
185	        eprintln!("set_threshold_via_socket_updates_dispatcher: socket never became ready — skipping");
186	        return;
187	    }
188	
189	    let resp = tokio::task::spawn_blocking(|| {
190	        send_command(ControlRequest::SetThreshold { threshold: 0.6 })
191	    })
192	    .await
193	    .expect("spawn_blocking panicked")
194	    .expect("send_command failed");
195	
196	    assert!(
197	        matches!(resp, ControlResponse::Ok),
198	        "expected Ok from SetThreshold, got: {resp:?}"
199	    );
200	
201	    // The handler must have forwarded exactly one RuntimeCommand::SetThreshold(0.6).
202	    let mut forwarded = Vec::new();
203	    while let Ok(cmd) = rt_rx.try_recv() {
204	        forwarded.push(cmd);
205	    }
206	    assert_eq!(forwarded.len(), 1, "expected exactly one RuntimeCommand forwarded, got {}", forwarded.len());
207	    match &forwarded[0] {
208	        RuntimeCommand::SetThreshold(t) => {
209	            assert!(
210	                (t - 0.6_f32).abs() < 1e-5,
211	                "expected SetThreshold(0.6), got SetThreshold({t})"
212	            );
213	        }
214	        other => panic!("expected SetThreshold, got: {other:?}"),
215	    }
216	}
