44	/// Receives STT transcripts, finds the best-matching macro phrase, and fires the macro.
45	///
46	/// The dispatcher is shared across threads via `Arc` (see `SAFETY` comments below).
47	/// Live macro registry updates arrive through [`Dispatcher::update_macros`] without
48	/// restarting the pipeline.
49	pub struct Dispatcher {
50	    state: DispatcherState,
51	    matcher: RwLock<PhraseMatcher>,
52	    macros: Arc<RwLock<Vec<MacroConfig>>>,
53	    sound_player: Option<SoundPlayer>,
54	    macro_tx: Sender<MacroCmd>,
55	    default_dwell_ms: u64,
56	    default_gap_ms: u64,
57	}
58	
59	// SAFETY: rodio's OutputStream (held inside SoundPlayer) is !Send, but Dispatcher only ever
60	// accesses sound_player from the single thread that owns it. No reference to sound_player is
61	// shared across threads, so manual Send is sound.
62	unsafe impl Send for Dispatcher {}
63	// SAFETY: same invariant as Send — all access to sound_player is serialised through the single
64	// owning thread; no concurrent access can occur across thread boundaries.
65	unsafe impl Sync for Dispatcher {}
66	
67	impl Dispatcher {
68	    /// Create a new `Dispatcher`.
69	    ///
70	    /// `threshold` is the minimum fuzzy-match score (0.0–1.0) for a phrase to fire.
71	    /// `default_dwell_ms` and `default_gap_ms` are applied to key steps that omit their own timing.
72	    pub fn new(
73	        threshold: f32,
74	        macros: Vec<MacroConfig>,
75	        macro_tx: Sender<MacroCmd>,
76	        default_dwell_ms: u64,
77	        default_gap_ms: u64,
78	    ) -> Self {
79	        let sound_player = match SoundPlayer::new() {
80	            Ok(player) => Some(player),
81	            Err(e) => {
82	                tracing::warn!("Sound player disabled: {}", e);
83	                None
84	            }
85	        };
86	
87	        Self {
88	            state: DispatcherState::new(),
89	            matcher: RwLock::new(PhraseMatcher::new(threshold)),
90	            macros: Arc::new(RwLock::new(macros)),
91	            sound_player,
92	            macro_tx,
93	            default_dwell_ms,
94	            default_gap_ms,
95	        }
96	    }
97	
98	    /// Replace the live macro registry without restarting the pipeline.
99	    pub fn update_macros(&self, new_macros: Vec<MacroConfig>) {
100	        let mut macros = self.macros.write().unwrap();
101	        *macros = new_macros;
102	        tracing::info!("Registry updated with {} macros", macros.len());
103	    }
104	
105	    /// Return the number of macros currently registered.
106	    pub fn macro_count(&self) -> usize {
107	        self.macros.read().unwrap().len()
108	    }
109	
110	    /// Return the current confidence threshold.
111	    pub fn threshold(&self) -> f32 {
112	        self.matcher.read().unwrap().threshold()
113	    }
114	
115	    /// Change the phrase-match confidence threshold without rebuilding the pipeline.
116	    ///
117	    /// `threshold` is clamped to `[0.0, 1.0]`; NaN is treated as 0.0.
118	    pub fn update_threshold(&self, threshold: f32) {
119	        let clamped = if threshold.is_nan() {
120	            0.0_f32
121	        } else {
122	            threshold.clamp(0.0, 1.0)
123	        };
124	        let old = self.matcher.read().unwrap().threshold();
125	        *self.matcher.write().unwrap() = PhraseMatcher::new(clamped);
126	        tracing::info!(old, new = clamped, "dispatcher threshold updated");
127	    }
128	
129	    fn check_condition(&self, if_flag: &Option<String>) -> bool {
130	        match if_flag {
131	            None => true,
132	            Some(if_flag) => {
133	                if let Some(stripped) = if_flag.strip_prefix('!') {
134	                    !self.state.get(stripped)
