142	    /// Match `transcript` against the macro registry and fire the best-scoring macro.
143	    ///
144	    /// Returns [`DispatchOutcome::Fired`] when a phrase matches above the threshold,
145	    /// or [`DispatchOutcome::NoMatch`] otherwise. Side effects: plays an optional
146	    /// sound file and sends a [`MacroCmd`] to the input injector.
147	    pub fn process(&self, transcript: &str) -> DispatchOutcome {
148	        let macros = self.macros.read().unwrap();
149	        let candidates = macros
150	            .iter()
151	            .filter(|m| self.check_condition(&m.if_flag))
152	            .filter_map(|m| m.phrase.as_ref().map(|p| (m.name.as_str(), p.as_str())));
153	
154	        if let Some((best_match_name, score)) = self.matcher.read().unwrap().find_best_match(transcript, candidates) {
155	            tracing::info!(macro_name = best_match_name, score, "Firing macro");
156	            if let Some(mac) = macros.iter().find(|m| m.name == best_match_name) {
157	                if let Some(sound_path) = &mac.sound {
158	                    if let Some(player) = &self.sound_player {
159	                        if let Err(e) = player.play(sound_path) {
160	                            tracing::error!("Failed to play sound for macro {}: {}", mac.name, e);
161	                        }
162	                    }
163	                }
164	
165	                let keys = mac.keys.iter().map(KeyStep::from_config).collect();
166	                let _ = self.macro_tx.send(MacroCmd::Execute {
167	                    keys,
168	                    default_dwell_ms: self.default_dwell_ms,
169	                    default_gap_ms: self.default_gap_ms,
170	                });
171	
172	                if let Some(set_flag) = &mac.set_flag {
173	                    if let Some(stripped) = set_flag.strip_prefix('!') {
174	                        self.state.set(stripped, false);
175	                    } else {
176	                        self.state.set(set_flag.as_str(), true);
177	                    }
178	                }
179	
180	                return DispatchOutcome::Fired {
181	                    macro_id: best_match_name.to_string(),
182	                    score,
183	                };
184	            }
185	        }
186	
187	        tracing::debug!(transcript, "No phrase matched above threshold");
188	        DispatchOutcome::NoMatch
189	    }
