191	    /// Fire a macro by exact name, bypassing phrase matching.
192	    ///
193	    /// Acquires a read lock on the macro registry, locates the first entry whose
194	    /// `name` equals `name`, plays its optional sound, sends `MacroCmd::Execute`
195	    /// to the injection thread, and returns `Ok(DispatchOutcome::Fired)` with
196	    /// `score: 1.0` (deliberate direct trigger convention).
197	    ///
198	    /// Returns `Err` when the macro is not found or the injection channel is closed.
199	    pub fn fire_named(&self, name: &str) -> Result<DispatchOutcome, String> {
200	        let macros = self.macros.read().unwrap();
201	        let mac = macros
202	            .iter()
203	            .find(|m| m.name == name)
204	            .ok_or_else(|| format!("macro not found: {name}"))?;
205	
206	        tracing::info!(macro_name = name, "Firing macro (direct)");
207	
208	        if let Some(sound_path) = &mac.sound {
209	            if let Some(player) = &self.sound_player {
210	                if let Err(e) = player.play(sound_path) {
211	                    tracing::error!("Failed to play sound for macro {}: {}", mac.name, e);
212	                }
213	            }
214	        }
215	
216	        let keys: Vec<KeyStep> = mac.keys.iter().map(KeyStep::from_config).collect();
217	        self.macro_tx
218	            .send(MacroCmd::Execute {
219	                keys,
220	                default_dwell_ms: self.default_dwell_ms,
221	                default_gap_ms: self.default_gap_ms,
222	            })
223	            .map_err(|e| format!("injection channel closed: {e}"))?;
224	
225	        Ok(DispatchOutcome::Fired {
226	            macro_id: name.into(),
227	            score: 1.0,
228	        })
229	    }
230	}
